 34→export async function setupEvalRuntime(suiteName: string): Promise<EvalRuntime> {
 35→  const namespace = `eval_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 36→  const database = `${suiteName}_${Math.floor(Math.random() * 100000)}`;
 37→
 38→  const surreal = new Surreal();
 39→  await surreal.connect(surrealUrl);
 40→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 41→
 42→  // SurrealDB can throw "Cannot perform subtraction with 'NONE'" during
 43→  // namespace/database operations when leftover computed fields exist.
 44→  // Swallow these benign errors during setup.
 45→  const setupQuery = async (sql: string) => {
 46→    await surreal.query(sql).catch((error) => {
 47→      if (!isAlreadyExistsError(error) && !isNoneSubtractionError(error)) throw error;
 48→    });
 49→  };
 50→  await setupQuery(`DEFINE NAMESPACE IF NOT EXISTS ${namespace};`);
 51→  await surreal.use({ namespace, database: undefined as any });
 52→  await setupQuery(`REMOVE DATABASE IF EXISTS ${database};`);
 53→  await setupQuery(`DEFINE DATABASE IF NOT EXISTS ${database};`);
 54→  await surreal.use({ namespace, database });
 55→
 56→  const schemaSql = readFileSync(schemaPath, "utf8");
 57→  // Split schema into individual statements to isolate errors.
 58→  // SurrealDB multi-statement queries can fail mid-batch; splitting lets us
 59→  // skip benign runtime errors (like subtraction on NONE in DEFINE FUNCTION
 60→  // validation) while still applying all schema definitions.
 61→  const schemaStatements = splitSurqlStatements(schemaSql);
 62→  for (const stmt of schemaStatements) {
 63→    await surreal.query(stmt).catch((error) => {
 64→      if (!isAlreadyExistsError(error) && !isNoneSubtractionError(error)) throw error;
 65→    });
 66→  }
 67→
 68→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 69→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 70→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 71→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 72→  const embeddingDimension = Number(requireEnv("EMBEDDING_DIMENSION"));
 73→  const extractionStoreThreshold = Number(process.env.EXTRACTION_STORE_THRESHOLD ?? "0.3");
 74→  const extractionDisplayThreshold = Number(process.env.EXTRACTION_DISPLAY_THRESHOLD ?? "0.5");
 75→
 76→  const openrouter = createOpenRouter({ apiKey: openRouterApiKey });
 77→  const extractionModel = openrouter(extractionModelId, { plugins: [{ id: "response-healing" }] });
 78→  const chatAgentModel = openrouter(chatAgentModelId, { plugins: [{ id: "response-healing" }] });
 79→  const embeddingModel = openrouter.textEmbeddingModel(embeddingModelId);
 80→
 81→  const pmAgentModelId = process.env.PM_AGENT_MODEL?.trim() || extractionModelId;
 82→  const analyticsAgentModelId = process.env.ANALYTICS_MODEL?.trim() || "unknown";
 83→
 84→  const config: ServerConfig = {
 85→    openRouterApiKey,
 86→    chatAgentModelId,
 87→    extractionModelId,
 88→    pmAgentModelId,
 89→    analyticsAgentModelId,
 90→    embeddingModelId,
 91→    embeddingDimension,
 92→    extractionStoreThreshold,
 93→    extractionDisplayThreshold,
 94→    surrealUrl,
 95→    surrealUsername,
 96→    surrealPassword,
 97→    surrealNamespace: namespace,
 98→    surrealDatabase: database,
 99→    port: 0,
100→  };
101→
102→  return {
103→    surreal,
104→    extractionModel,
105→    embeddingModel,
106→    chatAgentModel,
107→    config,
108→    namespace,
109→    database,
110→  };
111→}
