119→export async function seedWorkspace(surreal: Surreal, workspaceName?: string, nextId?: () => string): Promise<{
120→  workspaceRecord: RecordId<"workspace", string>;
121→  workspaceName: string;
122→  projectRecord: RecordId<"project", string>;
123→  conversationRecord: RecordId<"conversation", string>;
124→  ownerPersonCount: number;
125→}> {
126→  const id = nextId ?? randomUUID;
127→  const now = new Date();
128→  const resolvedWorkspaceName = workspaceName ?? `Eval ${Date.now()}`;
129→  const workspaceRecord = new RecordId("workspace", id());
130→  const projectRecord = new RecordId("project", id());
131→  const conversationRecord = new RecordId("conversation", id());
132→  const ownerRecord = new RecordId("identity", id());
133→
134→  await surreal.create(workspaceRecord).content({
135→    name: resolvedWorkspaceName,
136→    status: "active",
137→    onboarding_complete: false,
138→    onboarding_turn_count: 0,
139→    onboarding_summary_pending: false,
140→    onboarding_started_at: now,
141→    created_at: now,
142→    updated_at: now,
143→  });
144→
145→  await surreal.create(projectRecord).content({
146→    name: "Eval Project",
147→    status: "active",
148→    created_at: now,
149→    updated_at: now,
150→  });
151→
152→  // NOTE: Do NOT link default eval project to workspace via has_project.
153→  // Only workspace_seed projects should appear in workspace scope so the
154→  // extraction LLM sees the correct project list for project-vs-feature classification.
155→
156→  await surreal.create(ownerRecord).content({
157→    name: "Marcus",
158→    type: "human",
159→    workspace: workspaceRecord,
160→    identity_status: "active",
161→    created_at: now,
162→  });
163→
164→  await surreal.query(
165→    `RELATE $identity->member_of->$workspace SET role = 'owner', added_at = $now;`,
166→    { identity: ownerRecord, workspace: workspaceRecord, now },
167→  );
168→
169→  await surreal.create(conversationRecord).content({
170→    createdAt: now,
171→    updatedAt: now,
172→    workspace: workspaceRecord,
173→    source: "onboarding",
174→  });
175→
176→  return { workspaceRecord, workspaceName: resolvedWorkspaceName, projectRecord, conversationRecord, ownerPersonCount: 1 };
177→}
