179→export async function seedConversationContext(
180→  surreal: Surreal,
181→  conversationRecord: RecordId<"conversation", string>,
182→  context: Array<{ role: "user" | "assistant"; text: string }>,
183→  nextId?: () => string,
184→): Promise<string[]> {
185→  const id = nextId ?? randomUUID;
186→  const now = Date.now();
187→  const messageIds: string[] = [];
188→  for (const [index, message] of context.entries()) {
189→    const seededMessageRecord = new RecordId("message", id());
190→    await surreal.create(seededMessageRecord).content({
191→      conversation: conversationRecord,
192→      role: message.role,
193→      text: message.text,
194→      createdAt: new Date(now + index),
195→    });
196→    messageIds.push(seededMessageRecord.id as string);
197→  }
198→  return messageIds;
199→}
