231→export async function seedGraphEntities(
232→  surreal: Surreal,
233→  workspaceRecord: RecordId<"workspace", string>,
234→  projectRecord: RecordId<"project", string>,
235→  conversationRecord: RecordId<"conversation", string>,
236→  seeds: WorkspaceSeedItem[],
237→  nextId?: () => string,
238→): Promise<void> {
239→  const id = nextId ?? randomUUID;
240→  const now = new Date();
241→  const seedMessageRecord = new RecordId("message", id());
242→  await surreal.create(seedMessageRecord).content({
243→    conversation: conversationRecord,
244→    role: "assistant",
245→    text: "Workspace seed context.",
246→    createdAt: new Date(now.getTime() - 60_000),
247→  });
248→
249→  for (const seed of seeds) {
250→    const entityRecord = new RecordId(seed.kind, id());
251→    await surreal.create(entityRecord).content(buildSeedEntityContent(seed.kind, seed.text, now));
252→
253→    await surreal.relate(seedMessageRecord, new RecordId("extraction_relation", id()), entityRecord, {
254→      confidence: 0.95,
255→      extracted_at: now,
256→      created_at: now,
257→      model: "seed",
258→      from_text: seed.text,
259→      evidence: seed.text,
260→      evidence_source: seedMessageRecord,
261→    }).output("after");
262→
263→    if (seed.kind === "feature") {
264→      await surreal.relate(projectRecord, new RecordId("has_feature", id()), entityRecord as RecordId<"feature", string>, {
265→        added_at: now,
266→      }).output("after");
267→    }
268→
269→    if (seed.kind === "task" || seed.kind === "decision" || seed.kind === "question") {
270→      await surreal.relate(entityRecord, new RecordId("belongs_to", id()), projectRecord, {
271→        added_at: now,
272→      }).output("after");
273→    }
274→
275→    if (seed.kind === "project") {
276→      await surreal.relate(workspaceRecord, new RecordId("has_project", id()), entityRecord as RecordId<"project", string>, {
277→        added_at: now,
278→      }).output("after");
279→    }
280→  }
281→}
282→
283→function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
284→  const base = { created_at: now, updated_at: now };
285→  if (kind === "project") return { ...base, name: text, status: "active" };
286→  if (kind === "feature") return { ...base, name: text, status: "active" };
287→  if (kind === "task") return { ...base, title: text, status: "open" };
288→  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
289→  return { ...base, text, status: "open" };
290→}
291→
292→export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
293→  const events = new Map<string, StreamEvent[]>();
294→  return {
295→    registerMessage(messageId: string) {
296→      events.set(messageId, []);
297→    },
298→    handleStreamRequest(_messageId: string): Response {
299→      throw new Error("handleStreamRequest not available in eval mode");
300→    },
301→    emitEvent(messageId: string, event: StreamEvent) {
302→      events.get(messageId)?.push(event);
303→    },
304→    getEvents(messageId: string): StreamEvent[] {
305→      return events.get(messageId) ?? [];
306→    },
307→  };
308→}
309→
310→function isAlreadyExistsError(error: unknown): boolean {
311→  return error instanceof Error && error.message.includes("already exists");
312→}
313→
314→function isNoneSubtractionError(error: unknown): boolean {
315→  return error instanceof Error && error.message.includes("Cannot perform subtraction with 'NONE'");
316→}
317→
318→/**
319→ * Split a .surql file into individual top-level statements.
320→ * Handles BEGIN TRANSACTION...COMMIT TRANSACTION blocks as single units,
321→ * and DEFINE FUNCTION...}; blocks as single units.
322→ */
323→function splitSurqlStatements(sql: string): string[] {
324→  const lines = sql.split("\n");
325→  const statements: string[] = [];
326→  let current: string[] = [];
327→  let inTransaction = false;
328→  let inFunction = false;
329→
330→  for (const line of lines) {
331→    const trimmed = line.trim();
332→
333→    // Skip empty lines and comments at top level
334→    if (!inTransaction && !inFunction && (trimmed === "" || trimmed.startsWith("--"))) {
335→      continue;
336→    }
337→
338→    if (trimmed.startsWith("BEGIN TRANSACTION") || trimmed === "BEGIN TRANSACTION;") {
339→      inTransaction = true;
340→      current.push(line);
341→      continue;
342→    }
343→
344→    if (inTransaction) {
345→      current.push(line);
346→      if (trimmed.startsWith("COMMIT TRANSACTION") || trimmed === "COMMIT TRANSACTION;") {
347→        inTransaction = false;
348→        statements.push(current.join("\n"));
349→        current = [];
350→      }
351→      continue;
352→    }
353→
354→    if (trimmed.startsWith("DEFINE FUNCTION")) {
355→      inFunction = true;
356→      current.push(line);
357→      continue;
358→    }
359→
360→    if (inFunction) {
361→      current.push(line);
362→      if (trimmed === "};") {
363→        inFunction = false;
364→        statements.push(current.join("\n"));
365→        current = [];
366→      }
367→      continue;
368→    }
369→
370→    // Regular statement (single line ending with ;)
371→    if (trimmed.endsWith(";")) {
372→      current.push(line);
373→      statements.push(current.join("\n"));
374→      current = [];
375→    } else if (trimmed.length > 0) {
376→      // Multi-line statement continuation
377→      current.push(line);
378→    }
379→  }
380→
381→  if (current.length > 0) {
382→    statements.push(current.join("\n"));
383→  }
384→
385→  return statements.filter((s) => s.trim().length > 0);
386→}
387→
388→function requireEnv(name: string): string {
389→  const value = process.env[name];
390→  if (!value || value.trim().length === 0) {
391→    throw new Error(`Missing required environment variable: ${name}`);
392→  }
393→  return value;
394→}
