393→function assertAutoevalEnv(): void {
394→  const hasOpenAiKey = hasEnv("OPENAI_API_KEY");
395→  const hasBraintrustKey = hasEnv("BRAINTRUST_API_KEY");
396→  if (!hasOpenAiKey && !hasBraintrustKey) {
